{"content": "/* ===== Reset & Base ===== */
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  /* Primary */
  --clr-primary: hsl(246, 80%, 60%);

  /* Activity colours */
  --clr-work: hsl(15, 100%, 70%);
  --clr-play: hsl(195, 74%, 62%);
  --clr-study: hsl(348, 100%, 68%);
  --clr-exercise: hsl(145, 58%, 55%);
  --clr-social: hsl(264, 64%, 52%);
  --clr-self-care: hsl(43, 84%, 65%);

  /* Neutral */
  --clr-bg: hsl(226, 43%, 10%);
  --clr-card-bg: hsl(235, 46%, 20%);
  --clr-card-hover: hsl(235, 46%, 30%);
  --clr-text-muted: hsl(235, 45%, 61%);
  --clr-text-light: hsl(236, 100%, 87%);
  --clr-white: hsl(0, 0%, 100%);

  /* Font */
  --ff-body: 'Rubik', sans-serif;
  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
}

body {
  font-family: var(--ff-body);
  font-size: 18px;
  font-weight: var(--fw-regular);
  background-color: var(--clr-bg);
  color: var(--clr-white);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 2rem 1.5rem;
}

/* ===== Dashboard Grid ===== */
.dashboard {
  display: grid;
  gap: 1.5rem;
  width: 100%;
  max-width: 1110px;
}

/* Mobile: single column */
@media (min-width: 600px) {
  .dashboard {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (min-width: 1000px) {
  .dashboard {
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: auto auto;
  }

  .profile-card {
    grid-row: 1 / 3;
  }
}

/* ===== Profile Card ===== */
.profile-card {
  background-color: var(--clr-card-bg);
  border-radius: 15px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.profile-card__header {
  background-color: var(--clr-primary);
  border-radius: 15px;
  padding: 2rem;
  display: flex;
  align-items: center;
  gap: 1.25rem;
  flex: 1;
}

@media (min-width: 1000px) {
  .profile-card__header {
    flex-direction: column;
    align-items: flex-start;
    padding: 2.25rem 2rem 5rem;
  }
}

.profile-card__avatar {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  border: 3px solid var(--clr-white);
}

@media (min-width: 1000px) {
  .profile-card__avatar {
    width: 78px;
    height: 78px;
    margin-bottom: 0.5rem;
  }
}

.profile-card__label {
  font-size: 0.9375rem;
  font-weight: var(--fw-regular);
  color: var(--clr-text-light);
}

.profile-card__name {
  font-size: 1.5rem;
  font-weight: var(--fw-light);
  line-height: 1.2;
}

@media (min-width: 1000px) {
  .profile-card__name {
    font-size: 2.5rem;
  }
}

.profile-card__nav {
  display: flex;
  justify-content: space-around;
  padding: 1.5rem 2rem;
}

@media (min-width: 1000px) {
  .profile-card__nav {
    flex-direction: column;
    gap: 0.75rem;
    padding: 1.5rem 2rem 2rem;
  }
}

.profile-card__btn {
  background: none;
  border: none;
  color: var(--clr-text-muted);
  font-family: var(--ff-body);
  font-size: 1.125rem;
  font-weight: var(--fw-regular);
  cursor: pointer;
  transition: color 0.2s ease;
  padding: 0.25rem 0;
}

.profile-card__btn:hover,
.profile-card__btn:focus {
  color: var(--clr-white);
  outline: none;
}

.profile-card__btn.active {
  color: var(--clr-white);
}

/* ===== Activity Card ===== */
.activity-card {
  border-radius: 15px;
  overflow: hidden;
  position: relative;
}

.activity-card__banner {
  height: 38px;
  position: relative;
  overflow: hidden;
  display: flex;
  justify-content: flex-end;
  padding-right: 1rem;
}

.activity-card__banner img {
  width: 78px;
  height: 78px;
  margin-top: -10px;
}

/* Colours */
.activity-card--work { background-color: var(--clr-work); }
.activity-card--play { background-color: var(--clr-play); }
.activity-card--study { background-color: var(--clr-study); }
.activity-card--exercise { background-color: var(--clr-exercise); }
.activity-card--social { background-color: var(--clr-social); }
.activity-card--self-care { background-color: var(--clr-self-care); }

.activity-card__body {
  background-color: var(--clr-card-bg);
  border-radius: 15px;
  padding: 1.75rem 1.5rem;
  position: relative;
  z-index: 1;
  cursor: pointer;
  transition: background-color 0.2s ease;
}

.activity-card__body:hover {
  background-color: var(--clr-card-hover);
}

.activity-card__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.375rem;
}

.activity-card__title {
  font-size: 1.125rem;
  font-weight: var(--fw-medium);
}

.activity-card__ellipsis {
  background: none;
  border: none;
  cursor: pointer;
  padding: 0.25rem;
  display: flex;
  align-items: center;
}

.activity-card__ellipsis img {
  width: 21px;
  height: 5px;
}

.activity-card__ellipsis:hover img,
.activity-card__ellipsis:focus img {
  filter: brightness(2);
}

.activity-card__stats {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

@media (min-width: 1000px) {
  .activity-card__stats {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.5rem;
  }
}

.activity-card__hours {
  font-size: 2rem;
  font-weight: var(--fw-light);
  line-height: 1.2;
}

@media (min-width: 1000px) {
  .activity-card__hours {
    font-size: 3.5rem;
  }
}

.activity-card__previous {
  font-size: 0.9375rem;
  font-weight: var(--fw-regular);
  color: var(--clr-text-light);
}

/* ===== Attribution ===== */
.attribution {
  font-size: 11px;
  text-align: center;
  margin-top: 2rem;
  color: var(--clr-text-muted);
}

.attribution a {
  color: hsl(228, 45%, 44%);
}
