{"content": "// Time Tracking Dashboard - script.js
(function () {
  'use strict';

  const TIMEFRAME_LABELS = {
    daily: { current: 'Day', previous: 'Yesterday' },
    weekly: { current: 'Week', previous: 'Last Week' },
    monthly: { current: 'Month', previous: 'Last Month' }
  };

  const ACTIVITY_ICONS = {
    work: './images/icon-work.svg',
    play: './images/icon-play.svg',
    study: './images/icon-study.svg',
    exercise: './images/icon-exercise.svg',
    social: './images/icon-social.svg',
    'self care': './images/icon-self-care.svg'
  };

  let currentTimeframe = 'weekly';
  let activityData = [];

  /**
   * Slugify a title for use as a CSS class modifier.
   */
  function slugify(title) {
    return title.toLowerCase().replace(/\s+/g, '-');
  }

  /**
   * Format hours string, e.g. 1 -> "1hr", 5 -> "5hrs"
   */
  function formatHours(hrs) {
    return hrs === 1 ? '1hr' : hrs + 'hrs';
  }

  /**
   * Render all activity cards into the dashboard.
   */
  function renderCards(data, timeframe) {
    const dashboard = document.querySelector('.dashboard');

    // Remove existing activity cards
    document.querySelectorAll('.activity-card').forEach(function (card) {
      card.remove();
    });

    data.forEach(function (activity) {
      var slug = slugify(activity.title);
      var tf = activity.timeframes[timeframe];
      var label = TIMEFRAME_LABELS[timeframe];

      var card = document.createElement('article');
      card.className = 'activity-card activity-card--' + slug;
      card.setAttribute('data-activity', slug);

      card.innerHTML =
        '<div class="activity-card__banner">' +
          '<img src="' + (ACTIVITY_ICONS[activity.title.toLowerCase()] || '') + '" alt="' + activity.title + ' icon" aria-hidden="true">' +
        '</div>' +
        '<div class="activity-card__body">' +
          '<div class="activity-card__header">' +
            '<h2 class="activity-card__title">' + activity.title + '</h2>' +
            '<button class="activity-card__ellipsis" aria-label="More options for ' + activity.title + '">' +
              '<img src="./images/icon-ellipsis.svg" alt="">' +
            '</button>' +
          '</div>' +
          '<div class="activity-card__stats">' +
            '<p class="activity-card__hours">' + formatHours(tf.current) + '</p>' +
            '<p class="activity-card__previous">' + label.previous + ' - ' + formatHours(tf.previous) + '</p>' +
          '</div>' +
        '</div>';

      dashboard.appendChild(card);
    });
  }

  /**
   * Update existing cards without full re-render (for smooth switching).
   */
  function updateCards(timeframe) {
    var label = TIMEFRAME_LABELS[timeframe];

    activityData.forEach(function (activity) {
      var slug = slugify(activity.title);
      var card = document.querySelector('.activity-card[data-activity="' + slug + '"]');
      if (!card) return;

      var tf = activity.timeframes[timeframe];
      var hoursEl = card.querySelector('.activity-card__hours');
      var prevEl = card.querySelector('.activity-card__previous');

      if (hoursEl) hoursEl.textContent = formatHours(tf.current);
      if (prevEl) prevEl.textContent = label.previous + ' - ' + formatHours(tf.previous);
    });
  }

  /**
   * Set the active timeframe button.
   */
  function setActiveButton(timeframe) {
    document.querySelectorAll('.profile-card__btn').forEach(function (btn) {
      btn.classList.toggle('active', btn.getAttribute('data-timeframe') === timeframe);
    });
  }

  /**
   * Handle timeframe switching.
   */
  function switchTimeframe(timeframe) {
    if (timeframe === currentTimeframe) return;
    currentTimeframe = timeframe;
    setActiveButton(timeframe);
    updateCards(timeframe);
  }

  /**
   * Attach event listeners to nav buttons.
   */
  function initNav() {
    document.querySelectorAll('.profile-card__btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var tf = this.getAttribute('data-timeframe');
        if (tf) switchTimeframe(tf);
      });
    });
  }

  /**
   * Load data from data.json and bootstrap the UI.
   */
  function init() {
    fetch('./data.json')
      .then(function (response) {
        if (!response.ok) throw new Error('Failed to load data.json');
        return response.json();
      })
      .then(function (data) {
        activityData = data;
        renderCards(data, currentTimeframe);
        initNav();
      })
      .catch(function (err) {
        console.error('Error loading data:', err);
      });
  }

  // Boot
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
