{"content": "/**
 * test_dashboard.js – Headless browser test for Time Tracking Dashboard
 *
 * Validates DOM structure, data rendering, timeframe switching, hover/focus states,
 * responsiveness, and accessibility.  Outputs dashboard_report.json.
 *
 * Usage:  node test_dashboard.js
 */

const puppeteer = require('puppeteer-core');
const http = require('http');
const path = require('path');
const fs = require('fs');

const CHROME_PATH = '/tmp/home_1091/.cache/puppeteer/chrome-headless-shell/linux-147.0.7727.56/chrome-headless-shell-linux64/chrome-headless-shell';
const ROOT = __dirname;
const DATA = JSON.parse(fs.readFileSync(path.join(ROOT, 'data.json'), 'utf-8'));

const MIME = {
  '.html': 'text/html',
  '.css': 'text/css',
  '.js': 'application/javascript',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.svg': 'image/svg+xml',
};

function formatHours(h) {
  return h === 1 ? '1hr' : h + 'hrs';
}

/** Simple static file server */
function createServer() {
  return new Promise((resolve) => {
    const srv = http.createServer((req, res) => {
      let filePath = path.join(ROOT, decodeURIComponent(req.url === '/' ? '/index.html' : req.url));
      const ext = path.extname(filePath).toLowerCase();
      const mime = MIME[ext] || 'application/octet-stream';
      try {
        const data = fs.readFileSync(filePath);
        res.writeHead(200, { 'Content-Type': mime });
        res.end(data);
      } catch {
        res.writeHead(404);
        res.end('Not found');
      }
    });
    srv.listen(0, '127.0.0.1', () => {
      const port = srv.address().port;
      resolve({ srv, url: `http://127.0.0.1:${port}` });
    });
  });
}

(async () => {
  const report = { tests: [], summary: {} };
  let passed = 0;
  let failed = 0;

  function record(name, ok, details) {
    report.tests.push({ name, passed: ok, details: details || '' });
    if (ok) passed++;
    else failed++;
  }

  const { srv, url } = await createServer();
  console.log('Server on', url);

  const browser = await puppeteer.launch({
    headless: true,
    executablePath: CHROME_PATH,
    args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-gpu'],
  });

  const page = await browser.newPage();
  await page.setViewport({ width: 1440, height: 900 });
  await page.goto(url, { waitUntil: 'networkidle0', timeout: 15000 });

  // Wait for JS to render
  await page.waitForSelector('.activity-card', { timeout: 5000 }).catch(() => {});

  // ---------- 1. Page loads & has dashboard ----------
  const hasDashboard = await page.$('.dashboard');
  record('Dashboard container exists', !!hasDashboard);

  // ---------- 2. Profile card ----------
  const hasProfileCard = await page.$('.profile-card');
  record('Profile card exists', !!hasProfileCard);

  const profileName = await page.$eval('.profile-card__name', (el) => el.textContent.trim()).catch(() => '');
  record('Profile name is "Jeremy Robson"', profileName === 'Jeremy Robson', `Got: "${profileName}"`);

  const avatar = await page.$('.profile-card__avatar');
  record('Profile avatar image exists', !!avatar);

  // ---------- 3. Nav buttons ----------
  const navButtons = await page.$$('.profile-card__btn');
  record('Three timeframe buttons exist', navButtons.length === 3, `Found ${navButtons.length}`);

  const btnLabels = await page.$$eval('.profile-card__btn', (btns) => btns.map((b) => b.textContent.trim()));
  record(
    'Buttons labelled Daily/Weekly/Monthly',
    JSON.stringify(btnLabels) === JSON.stringify(['Daily', 'Weekly', 'Monthly']),
    `Got: ${JSON.stringify(btnLabels)}`
  );

  // ---------- 4. Activity cards rendered ----------
  const activityCards = await page.$$('.activity-card');
  record('Six activity cards rendered', activityCards.length === 6, `Found ${activityCards.length}`);

  // ---------- 5. Default timeframe is weekly ----------
  const weeklyBtn = await page.$('.profile-card__btn[data-timeframe="weekly"]');
  const weeklyActive = weeklyBtn ? await page.evaluate((el) => el.classList.contains('active'), weeklyBtn) : false;
  record('Weekly button is active by default', weeklyActive);

  // Check data for weekly
  for (const activity of DATA) {
    const slug = activity.title.toLowerCase().replace(/\s+/g, '-');
    const card = await page.$('.activity-card[data-activity="' + slug + '"]');
    if (!card) {
      record(`Card "${activity.title}" exists`, false, 'Card not found');
      continue;
    }

    const hours = await card.$eval('.activity-card__hours', (el) => el.textContent.trim()).catch(() => '');
    const expected = formatHours(activity.timeframes.weekly.current);
    record(`${activity.title} weekly hours = "${expected}"`, hours === expected, `Got: "${hours}"`);

    const prev = await card.$eval('.activity-card__previous', (el) => el.textContent.trim()).catch(() => '');
    const expectedPrev = 'Last Week - ' + formatHours(activity.timeframes.weekly.previous);
    record(`${activity.title} weekly previous = "${expectedPrev}"`, prev === expectedPrev, `Got: "${prev}"`);
  }

  // ---------- 6. Switch to Daily ----------
  const dailyBtn = await page.$('.profile-card__btn[data-timeframe="daily"]');
  if (dailyBtn) {
    await dailyBtn.click();
    await new Promise((r) => setTimeout(r, 500));

    const dailyActive = await page.evaluate((el) => el.classList.contains('active'), dailyBtn);
    record('Daily button becomes active after click', dailyActive);

    for (const activity of DATA) {
      const slug = activity.title.toLowerCase().replace(/\s+/g, '-');
      const card = await page.$('.activity-card[data-activity="' + slug + '"]');
      if (!card) continue;

      const hours = await card.$eval('.activity-card__hours', (el) => el.textContent.trim()).catch(() => '');
      const expected = formatHours(activity.timeframes.daily.current);
      record(`${activity.title} daily hours = "${expected}"`, hours === expected, `Got: "${hours}"`);

      const prev = await card.$eval('.activity-card__previous', (el) => el.textContent.trim()).catch(() => '');
      const expectedPrev = 'Yesterday - ' + formatHours(activity.timeframes.daily.previous);
      record(`${activity.title} daily previous = "${expectedPrev}"`, prev === expectedPrev, `Got: "${prev}"`);
    }
  } else {
    record('Daily button exists', false);
  }

  // ---------- 7. Switch to Monthly ----------
  const monthlyBtn = await page.$('.profile-card__btn[data-timeframe="monthly"]');
  if (monthlyBtn) {
    await monthlyBtn.click();
    await new Promise((r) => setTimeout(r, 500));

    const monthlyActive = await page.evaluate((el) => el.classList.contains('active'), monthlyBtn);
    record('Monthly button becomes active after click', monthlyActive);

    for (const activity of DATA) {
      const slug = activity.title.toLowerCase().replace(/\s+/g, '-');
      const card = await page.$('.activity-card[data-activity="' + slug + '"]');
      if (!card) continue;

      const hours = await card.$eval('.activity-card__hours', (el) => el.textContent.trim()).catch(() => '');
      const expected = formatHours(activity.timeframes.monthly.current);
      record(`${activity.title} monthly hours = "${expected}"`, hours === expected, `Got: "${hours}"`);

      const prev = await card.$eval('.activity-card__previous', (el) => el.textContent.trim()).catch(() => '');
      const expectedPrev = 'Last Month - ' + formatHours(activity.timeframes.monthly.previous);
      record(`${activity.title} monthly previous = "${expectedPrev}"`, prev === expectedPrev, `Got: "${prev}"`);
    }
  } else {
    record('Monthly button exists', false);
  }

  // ---------- 8. Hover states ----------
  try {
    const firstCardBody = await page.$('.activity-card__body');
    if (firstCardBody) {
      const bgBefore = await page.evaluate((el) => getComputedStyle(el).backgroundColor, firstCardBody);
      await firstCardBody.hover();
      await new Promise((r) => setTimeout(r, 300));
      const bgAfter = await page.evaluate((el) => getComputedStyle(el).backgroundColor, firstCardBody);
      record('Card body has hover state (bg changes)', bgBefore !== bgAfter, `Before: ${bgBefore}, After: ${bgAfter}`);
    }
  } catch (e) {
    record('Card body hover state', false, e.message);
  }

  // ---------- 9. Responsive layout ----------
  await page.setViewport({ width: 375, height: 800 });
  await new Promise((r) => setTimeout(r, 300));
  const mobileGrid = await page.evaluate(() => {
    const dash = document.querySelector('.dashboard');
    return dash ? getComputedStyle(dash).gridTemplateColumns : '';
  });
  const mobileCols = mobileGrid.trim().split(/\s+/).length;
  record('Mobile layout is single column', mobileCols === 1, `grid-template-columns: ${mobileGrid} (${mobileCols} cols)`);

  await page.setViewport({ width: 1440, height: 900 });
  await new Promise((r) => setTimeout(r, 300));
  const desktopGrid = await page.evaluate(() => {
    const dash = document.querySelector('.dashboard');
    return dash ? getComputedStyle(dash).gridTemplateColumns : '';
  });
  const desktopCols = desktopGrid.trim().split(/\s+/).length;
  record('Desktop layout has 4 columns', desktopCols === 4, `grid-template-columns: ${desktopGrid} (${desktopCols} cols)`);

  // ---------- 10. Font family ----------
  const fontFamily = await page.evaluate(() => getComputedStyle(document.body).fontFamily);
  record('Font family includes Rubik', fontFamily.toLowerCase().includes('rubik'), `Got: ${fontFamily}`);

  // ---------- 11. Background colour ----------
  const bgColor = await page.evaluate(() => getComputedStyle(document.body).backgroundColor);
  record('Body has dark background', bgColor !== 'rgba(0, 0, 0, 0)' && bgColor !== 'rgb(255, 255, 255)', `Got: ${bgColor}`);

  // ---------- 12. Activity card colour classes ----------
  const colorClasses = await page.$$eval('.activity-card', (cards) =>
    cards.map((c) => {
      const classes = Array.from(c.classList);
      return classes.find((cls) => cls.startsWith('activity-card--')) || '';
    })
  );
  const expectedClasses = ['activity-card--work', 'activity-card--play', 'activity-card--study', 'activity-card--exercise', 'activity-card--social', 'activity-card--self-care'];
  record(
    'Each card has correct colour modifier class',
    JSON.stringify(colorClasses.sort()) === JSON.stringify(expectedClasses.sort()),
    `Got: ${JSON.stringify(colorClasses)}`
  );

  // ---------- 13. Ellipsis buttons ----------
  const ellipsisBtns = await page.$$('.activity-card__ellipsis');
  record('Each card has ellipsis button', ellipsisBtns.length === 6, `Found ${ellipsisBtns.length}`);

  // ---------- 14. Banner icons ----------
  const bannerIcons = await page.$$('.activity-card__banner img');
  record('Each card has banner icon', bannerIcons.length === 6, `Found ${bannerIcons.length}`);

  // ---------- 15. Accessibility: h1 for name ----------
  const h1Count = await page.$$eval('h1', (els) => els.length);
  record('Page has exactly one h1 element', h1Count === 1, `Found ${h1Count}`);

  // ---------- 16. Accessibility: h2 for card titles ----------
  const h2Count = await page.$$eval('h2.activity-card__title', (els) => els.length);
  record('Six h2 elements for card titles', h2Count === 6, `Found ${h2Count}`);

  // ---------- 17. data-timeframe attribute on buttons ----------
  const tfAttrs = await page.$$eval('.profile-card__btn', (btns) =>
    btns.map((b) => b.getAttribute('data-timeframe'))
  );
  record(
    'Buttons have data-timeframe attributes',
    JSON.stringify(tfAttrs) === JSON.stringify(['daily', 'weekly', 'monthly']),
    `Got: ${JSON.stringify(tfAttrs)}`
  );

  // ---------- 18. data-activity attributes on cards ----------
  const actAttrs = await page.$$eval('.activity-card', (cards) =>
    cards.map((c) => c.getAttribute('data-activity'))
  );
  const expectedActs = ['work', 'play', 'study', 'exercise', 'social', 'self-care'];
  record(
    'Cards have data-activity attributes',
    JSON.stringify(actAttrs) === JSON.stringify(expectedActs),
    `Got: ${JSON.stringify(actAttrs)}`
  );

  // ---------- Done ----------
  report.summary = { total: passed + failed, passed, failed };

  await browser.close();
  srv.close();

  fs.writeFileSync(
    path.resolve(__dirname, 'dashboard_report.json'),
    JSON.stringify(report, null, 2)
  );

  console.log(`\n✅ Tests complete: ${passed} passed, ${failed} failed out of ${passed + failed}`);
  console.log('Report saved to dashboard_report.json');
})();
